import{c as e,Q as a,j as n,m as s}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"007-mini-kernel-intr-3 · 中断处理","description":"","frontmatter":{"title":"007-mini-kernel-intr-3 · 中断处理"},"headers":[],"relativePath":"hands-on/007-mini-kernel-intr-3.md","filePath":"hands-on/007-mini-kernel-intr-3.md","lastUpdated":1779686691000}'),r={name:"hands-on/007-mini-kernel-intr-3.md"};function i(p,t,o,d,l,h){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="_007-3-hands-on-isr-stub-与异常处理-—-触发异常不死机" tabindex="-1">007-3 Hands-on: ISR Stub 与异常处理 — 触发异常不死机 <a class="header-anchor" href="#_007-3-hands-on-isr-stub-与异常处理-—-触发异常不死机" aria-label="Permalink to &quot;007-3 Hands-on: ISR Stub 与异常处理 — 触发异常不死机&quot;">​</a></h1><blockquote><p>标签：ISR, Interrupt Frame, 汇编, IRETQ, CR2, Page Fault, int $3 前置：<a href="./007-mini-kernel-intr-2">007-2 IDT</a></p></blockquote><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>前两篇我们把 GDT 和 IDT 的数据结构和初始化都搭好了，但 IDT 里指向的 ISR stub 还没写——也就是说，虽然 CPU 知道该跳到哪里去处理异常，但跳过去之后发现那里什么都没有。这一篇我们要把最后几块拼图补齐：用汇编编写 ISR stub 保存寄存器，用 C 编写异常处理函数打印信息，最后在 main 里用 <code>int $3</code> 做一次完整的点火测试。</p><p>完成本篇后，我们就能在串口看到完整的寄存器 dump 和异常信息，而且执行不会中断——触发异常不死机，这就是 milestone 007 的最终目标。</p><p>本篇完成后你会新增两个文件：<code>kernel/mini/arch/x86_64/interrupts.S</code>（ISR stub 汇编）和 <code>kernel/mini/arch/x86_64/exception_handlers.cpp</code>（C 异常处理函数），同时更新 <code>kernel/mini/main.cpp</code>（添加 int $3 测试）和 <code>kernel/mini/CMakeLists.txt</code>（添加新源文件）。</p><hr><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="中断栈帧是怎么回事" tabindex="-1">中断栈帧是怎么回事？ <a class="header-anchor" href="#中断栈帧是怎么回事" aria-label="Permalink to &quot;中断栈帧是怎么回事？&quot;">​</a></h3><p>当 CPU 响应异常时，它会自动把当前的 SS、RSP、RFLAGS、CS、RIP 压入栈中（注意顺序是从高地址到低地址）。对于某些异常（比如 #PF），CPU 还会额外压入一个错误码。然后 CPU 跳转到 IDT 中指定的处理程序地址。</p><p>我们的 ISR stub（汇编写的）在 CPU 压栈的基础上，再把所有通用寄存器保存到栈上，加上一个统一的错误码字段（没有硬件错误码的异常就填 0），这样就形成了一个完整的 InterruptFrame 结构体。C 处理函数收到这个结构体的指针，就能读取异常发生时的完整 CPU 状态。</p><h3 id="at-t-汇编语法速查" tabindex="-1">AT&amp;T 汇编语法速查 <a class="header-anchor" href="#at-t-汇编语法速查" aria-label="Permalink to &quot;AT&amp;T 汇编语法速查&quot;">​</a></h3><p>我们的 ISR stub 用 GNU AS（AT&amp;T 语法）编写，几个关键区别需要记住：操作数顺序是&quot;源, 目标&quot;（和 Intel 语法相反），寄存器前缀用百分号 <code>%</code>，立即数前缀用美元符号 <code>$</code>，内存寻址格式是 <code>offset(base)</code>。比如 <code>pushq %rax</code> 是把 RAX 的值压栈，<code>pushq $0</code> 是压入数字 0，<code>8(%rsp)</code> 是访问 RSP+8 处的内存。</p><h3 id="为什么-bp-能安全测试而-pf-不行" tabindex="-1">为什么 #BP 能安全测试而 #PF 不行？ <a class="header-anchor" href="#为什么-bp-能安全测试而-pf-不行" aria-label="Permalink to &quot;为什么 #BP 能安全测试而 #PF 不行？&quot;">​</a></h3><p>#BP 是 Trap 类型的异常，CPU 压入的 RIP 指向触发指令的下一条——也就是说 IRETQ 返回后会继续执行后续代码，不会反复触发。而 #PF 是 Fault 类型的异常，CPU 压入的 RIP 指向触发指令本身——如果不修复页表就 IRETQ 返回，CPU 会重新执行同一条访存指令，再次触发 #PF，形成死循环。所以我们的 <code>int $3</code> 测试可以安全返回，但故意触发 #PF 就需要特殊处理（比如修改 frame 里的 RIP 跳过触发指令）。</p><hr><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-编写-isr-noerrcode-宏-处理-bp" tabindex="-1">Step 1: 编写 ISR_NOERRCODE 宏（处理 #BP） <a class="header-anchor" href="#step-1-编写-isr-noerrcode-宏-处理-bp" aria-label="Permalink to &quot;Step 1: 编写 ISR_NOERRCODE 宏（处理 #BP）&quot;">​</a></h3><p><strong>目标</strong>：用 AT&amp;T 汇编写一个宏，生成没有硬件错误码的异常的 ISR stub。</p><p><strong>设计思路</strong>：这个宏需要做以下几件事——首先压入伪错误码 0（保持栈帧统一），然后按固定顺序保存所有 15 个通用寄存器（rax, rbx, rcx, rdx, rbp, rsi, rdi, r8-r15），把当前栈指针作为第一个参数传给 C 处理函数（AT&amp;T 调用约定，第一个参数放 RDI），调用 C 处理函数，然后反向恢复所有寄存器，弹出伪错误码，最后用 IRETQ 返回。</p><p><strong>实现约束</strong>：宏接受三个参数——stub 名称、向量号、C 处理函数名。宏生成的符号需要用 <code>.global</code> 导出（让链接器能看到），用 <code>.type name, @function</code> 标注类型。寄存器的 push 顺序必须和 InterruptFrame 结构体中字段的声明顺序完全一致——结构体从上到下是 r15, r14, ..., rax，但压栈是反向的（先 push rax，最后 push r15），因为栈是从高地址往低地址增长的，先压的在栈底（低地址），对应结构体的靠前成员。</p><p><strong>踩坑预警</strong>：对于 #BP 这种没有硬件错误码的异常，CPU 只压入了 SS/RSP/RFLAGS/CS/RIP 五个值（5x8=40 字节）。如果 ISR stub 不手动压一个伪错误码，C 处理函数读到的 <code>frame-&gt;error_code</code> 实际上是 CPU 压的 RIP——整个结构体全部错位。这是一个极其隐蔽的 bug，因为它不会立刻 crash，而是让你的寄存器 dump 全部显示错误的值。</p><p><strong>验证</strong>：此步没有独立验证，和后续步骤一起验证。</p><h3 id="step-2-编写-isr-errcode-宏-处理-pf" tabindex="-1">Step 2: 编写 ISR_ERRCODE 宏（处理 #PF） <a class="header-anchor" href="#step-2-编写-isr-errcode-宏-处理-pf" aria-label="Permalink to &quot;Step 2: 编写 ISR_ERRCODE 宏（处理 #PF）&quot;">​</a></h3><p><strong>目标</strong>：写一个类似的宏，但用于 CPU 自动压入错误码的异常。</p><p><strong>设计思路</strong>：和 ISR_NOERRCODE 几乎一模一样，唯一区别是不需要手动压伪错误码——CPU 在进入 ISR 之前已经帮你压了。恢复时仍然用 <code>addq $8, %rsp</code> 跳过错误码（CPU 压的），然后 IRETQ。</p><p><strong>踩坑预警</strong>：不要混淆两个宏的用途！如果把 #PF（有错误码的异常）错用了 ISR_NOERRCODE 宏，就会多压一个 0，导致栈帧多出 8 字节，所有后续字段的偏移全部错位。反过来如果 #BP 错用了 ISR_ERRCODE 宏，就会缺少伪错误码，同样错位。每个异常是否有错误码是硬件固定的，可以查 Intel SDM Table 6-1。</p><p><strong>验证</strong>：此步没有独立验证。</p><h3 id="step-3-实例化两个-isr-stub" tabindex="-1">Step 3: 实例化两个 ISR Stub <a class="header-anchor" href="#step-3-实例化两个-isr-stub" aria-label="Permalink to &quot;Step 3: 实例化两个 ISR Stub&quot;">​</a></h3><p><strong>目标</strong>：用上面两个宏分别生成 isr_bp_stub 和 isr_pf_stub。</p><p><strong>实现约束</strong>：ISR_NOERRCODE 生成 isr_bp_stub，向量号 3，C handler 名 handle_bp。ISR_ERRCODE 生成 isr_pf_stub，向量号 14，C handler 名 handle_pf。这两个 stub 符号需要在 idt.cpp 中用 <code>extern &quot;C&quot;</code> 声明，以便 C++ 代码能引用它们的地址。</p><p><strong>验证</strong>：编译通过即可。</p><h3 id="step-4-实现-dump-interrupt-frame-辅助函数" tabindex="-1">Step 4: 实现 dump_interrupt_frame 辅助函数 <a class="header-anchor" href="#step-4-实现-dump-interrupt-frame-辅助函数" aria-label="Permalink to &quot;Step 4: 实现 dump_interrupt_frame 辅助函数&quot;">​</a></h3><p><strong>目标</strong>：写一个辅助函数，把 InterruptFrame 的所有字段格式化打印到串口。</p><p><strong>设计思路</strong>：打印内容包括异常名称和向量号、RIP/CS/RFLAGS/RSP/SS（CPU 自动压入的关键状态）、全部 15 个通用寄存器（ISR stub 保存的）以及错误码。输出格式设计成表格样式，方便在串口终端上快速扫读。dump 函数被 handle_bp 和 handle_pf 共用，放在匿名命名空间中避免符号泄露。</p><p><strong>实现约束</strong>：函数签名为 <code>void dump_interrupt_frame(const InterruptFrame* frame, const char* vec_name, uint8_t vector)</code>。放在匿名命名空间中，使用 <code>using cinux::mini::arch::InterruptFrame</code> 和 <code>using cinux::mini::lib::kprintf</code> 简化类型引用。RIP/RFLAGS 用 16 位十六进制打印（<code>%016x</code>），CS/SS 用 4 位打印（<code>%04x</code>）。</p><p><strong>验证</strong>：此步没有独立验证。</p><h3 id="step-5-实现-handle-bp-异常处理函数" tabindex="-1">Step 5: 实现 handle_bp 异常处理函数 <a class="header-anchor" href="#step-5-实现-handle-bp-异常处理函数" aria-label="Permalink to &quot;Step 5: 实现 handle_bp 异常处理函数&quot;">​</a></h3><p><strong>目标</strong>：写一个 C 函数，通过 kprintf 打印断点异常信息和寄存器 dump。</p><p><strong>设计思路</strong>：先调用 dump_interrupt_frame 打印完整的寄存器快照，然后额外打印断点地址（frame-&gt;rip）和提示信息。因为 #BP 是 Trap 类型，RIP 已经指向下一条指令，所以可以安全返回。</p><p><strong>实现约束</strong>：函数必须用 <code>extern &quot;C&quot;</code> 声明——这是因为 interrupts.S 里的 <code>call handle_bp</code> 是 C 链接约定，如果用 C++ 的 name mangling 的话链接器会找不到符号。函数签名是 <code>extern &quot;C&quot; void handle_bp(InterruptFrame* frame)</code>。</p><p><strong>验证</strong>：此步没有独立验证，和最终整合一起验证。</p><h3 id="step-6-实现-handle-pf-异常处理函数" tabindex="-1">Step 6: 实现 handle_pf 异常处理函数 <a class="header-anchor" href="#step-6-实现-handle-pf-异常处理函数" aria-label="Permalink to &quot;Step 6: 实现 handle_pf 异常处理函数&quot;">​</a></h3><p><strong>目标</strong>：写一个 C 函数，读取 CR2 寄存器，解析页错误码，打印详细的页错误信息。</p><p><strong>设计思路</strong>：CR2 寄存器是 x86 架构专门为页错误保留的——CPU 在触发 #PF 时会自动把导致缺页的线性地址写入 CR2，所以我们在处理函数里第一时间把它读出来（用内联汇编 <code>movq %%cr2, %0</code>）。然后解析 frame-&gt;error_code 的各个位：bit 0 区分&quot;页不存在&quot;和&quot;权限冲突&quot;，bit 1 区分读还是写，bit 2 区分内核态还是用户态，bit 3 是保留位冲突，bit 4 是指令缺页。这些信息在调试缺页问题的时候非常关键。</p><p><strong>踩坑预警</strong>：必须在进入 C 处理函数后第一时间读取 CR2——因为 kprintf 内部的任何内存操作都可能触发另一个页错误（虽然不太可能），覆盖 CR2 的值。虽然在这个简单的 mini kernel 里不太会出问题，但养成好习惯总是对的。</p><p><strong>验证</strong>：此步没有独立验证。</p><h3 id="step-7-整合到-main-cpp-—-用-int-3-点火测试" tabindex="-1">Step 7: 整合到 main.cpp — 用 int $3 点火测试 <a class="header-anchor" href="#step-7-整合到-main-cpp-—-用-int-3-点火测试" aria-label="Permalink to &quot;Step 7: 整合到 main.cpp — 用 int $3 点火测试&quot;">​</a></h3><p><strong>目标</strong>：在 mini_kernel_main 中，PMM 初始化完成后触发断点异常，验证整个中断链路。</p><p><strong>设计思路</strong>：用内联汇编 <code>__asm__ volatile(&quot;int $3&quot;)</code> 触发 #BP 异常。如果一切配置正确，执行流程是：int $3 -&gt; CPU 查 IDT[3] 得到 isr_bp_stub 地址 -&gt; 查 GDT[1] 确认 code64 段有效 -&gt; 压栈 SS/RSP/RFLAGS/CS/RIP -&gt; 跳转到 isr_bp_stub -&gt; stub 保存寄存器 -&gt; 调用 handle_bp -&gt; 打印寄存器 dump -&gt; 返回 stub -&gt; 恢复寄存器 -&gt; IRETQ -&gt; 继续执行 int $3 后面的代码。</p><p><strong>踩坑预警</strong>：别忘了 include 新文件的头文件（gdt.hpp 和 idt.hpp），也别忘了把新源文件加入 CMakeLists.txt——包括 idt.cpp、interrupts.S 和 exception_handlers.cpp。最容易被忽略的是 .S 文件——如果只添加了 .cpp 文件但漏了 .S 文件，链接时就会报 undefined reference。另一个常见的遗漏是 <code>arch/x86_64/gdt.cpp</code>——如果上一篇忘了加，这一篇构建也会失败。</p><p><strong>验证</strong>：完整构建运行后应该看到如下输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[TEST] Triggering breakpoint exception (int $3)...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>==== EXCEPTION: #BP (vector 3) ====</span></span>
<span class="line"><span>  RIP   = 0xffffffff80020xxx   CS  = 0x0008</span></span>
<span class="line"><span>  RFLAGS= 0x0000000000000046</span></span>
<span class="line"><span>  RSP   = 0xffffffff80025xxx   SS  = 0x0010</span></span>
<span class="line"><span>  RAX=0x...  RBX=0x...  ...  R15=0x...</span></span>
<span class="line"><span>  ERROR CODE = 0x0000000000000000</span></span>
<span class="line"><span>========================================</span></span>
<span class="line"><span>[EXCEPTION] Breakpoint triggered at RIP=0xffffffff80020xxx</span></span>
<span class="line"><span>[EXCEPTION] This is a software breakpoint, continuing...</span></span>
<span class="line"><span>[TEST] Breakpoint test passed! Execution continued after #BP.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>看到 <code>[TEST] Breakpoint test passed!</code> 就说明整个链路通了：GDT -&gt; IDT -&gt; ISR stub -&gt; C handler -&gt; IRETQ -&gt; 继续执行。</p><hr><h2 id="概念补充-完整的中断处理流程" tabindex="-1">概念补充：完整的中断处理流程 <a class="header-anchor" href="#概念补充-完整的中断处理流程" aria-label="Permalink to &quot;概念补充：完整的中断处理流程&quot;">​</a></h2><p>把整个 tag 007 的组件串起来看，一次完整的异常处理流程是这样的：</p><ol><li><strong>异常触发</strong>：CPU 执行 <code>int $3</code> 指令，产生 #BP 异常（向量 3）</li><li><strong>CPU 自动压栈</strong>：SS -&gt; RSP -&gt; RFLAGS -&gt; CS -&gt; RIP（注意 #BP 没有错误码）</li><li><strong>查 IDT</strong>：CPU 用向量号 3 查 IDT[3]，得到 selector=0x08 和 handler 地址=isr_bp_stub</li><li><strong>查 GDT</strong>：CPU 用 selector 0x08 查 GDT[1]，验证 code64 段有效（Present=1, L=1）</li><li><strong>跳转 ISR stub</strong>：CPU 跳转到 isr_bp_stub，我们的汇编代码开始执行</li><li><strong>保存寄存器</strong>：stub 压入伪错误码 0，然后保存 rax~r15 共 15 个通用寄存器</li><li><strong>调用 C handler</strong>：stub 把 RSP 作为 InterruptFrame* 传给 handle_bp（通过 RDI）</li><li><strong>打印信息</strong>：handle_bp 调用 dump_interrupt_frame 打印完整寄存器快照，然后打印断点地址</li><li><strong>返回 stub</strong>：handle_bp 返回，stub 开始恢复寄存器</li><li><strong>恢复寄存器</strong>：逆序 pop r15~rax，addq $8 跳过伪错误码</li><li><strong>IRETQ</strong>：CPU 从栈上弹出 RIP/CS/RFLAGS/RSP/SS，恢复到被中断的代码</li><li><strong>继续执行</strong>：RIP 指向 <code>int $3</code> 的下一条指令，内核继续运行</li></ol><p>这个流程中有多个环节可能出错：GDT 没配好导致步骤 4 失败、IDT 条目错误导致步骤 3 失败、ISR stub 的 push 顺序错误导致步骤 6-7 的 InterruptFrame 错位。每一步都需要仔细验证。</p><hr><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DCMAKE_BUILD_TYPE=Debug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nproc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>ISR stub 里寄存器保存顺序错乱</strong></p><p>对比 InterruptFrame 结构体的字段顺序和汇编中的 push 顺序。记住：第一个 push 的值在栈顶（最低地址），对应结构体最后一个字段。我们的结构体最后三个字段是 rcx/rbx/rax，所以汇编里先 push rax，再 push rbx，最后 push rcx。如果顺序搞反了，寄存器 dump 里显示的值就会互相串位。</p><p><strong>用 GDB 验证 InterruptFrame</strong></p><p>在 QEMU 调试模式下可以用以下命令：</p><ol><li><code>break handle_bp</code> 设断点</li><li><code>continue</code> 继续，触发 #BP 后断在 handle_bp</li><li><code>print *frame</code> 检查 frame-&gt;rip 是否指向 int $3 的下一条指令</li><li><code>info registers</code> 对比 frame 里的寄存器值和当前寄存器值</li></ol><p>特别关注 frame-&gt;rip 和 frame-&gt;error_code 的值。frame-&gt;rip 应该比 <code>int $3</code> 指令的地址大 1 或 2（取决于 int $3 的编码方式——0xCC 是 1 字节，0xCD 0x03 是 2 字节），因为 #BP 是 Trap 类型。frame-&gt;error_code 应该是 0（因为 ISR_NOERRCODE 压入了伪错误码 $0）。如果 error_code 不是 0，说明栈帧错位了。</p><p><strong>handle_pf 触发后死循环</strong></p><p>这是预期行为——#PF 是 Fault 类型，IRETQ 返回后会重新执行触发缺页的指令。如果不修复页表，就会反复触发 #PF。当前 handle_pf 只打印信息不修复页表，所以故意触发 #PF 会导致死循环打印。这在后续加入 VMM 后会改变。</p><p><strong>int $3 触发后没有输出就 triple fault 了</strong></p><p>逐层排查：(1) GDT 是否正确加载？检查 CS 是否为 0x0008。(2) IDT 是否正确加载？检查 IDT[3] 的 Present 位是否为 1。(3) ISR stub 地址是否正确？在 GDB 中 <code>print isr_bp_stub</code> 和 <code>x/2xg &amp;s_idt[3]</code> 对比。(4) stub 内部是否正确？在 <code>isr_bp_stub</code> 设断点单步执行。最常见的原因是 IDT 没加载（忘了调用 idt_init）或者 GDT/IDT 的 base 地址填错了。</p><hr><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>关键机制</th><th>说明</th></tr></thead><tbody><tr><td>ISR_NOERRCODE 宏</td><td>push $0 + push 寄存器 + call handler + pop + addq $8 + iretq</td><td>无错误码异常的 stub</td></tr><tr><td>ISR_ERRCODE 宏</td><td>push 寄存器 + call handler + pop + addq $8 + iretq</td><td>有错误码异常的 stub</td></tr><tr><td>handle_bp</td><td>dump frame + 打印断点地址</td><td>Trap 类型，IRETQ 后继续执行</td></tr><tr><td>handle_pf</td><td>读 CR2 + 解析 error_code + dump</td><td>Fault 类型，不修复页表会死循环</td></tr><tr><td>关键寄存器</td><td>CR2, RDI</td><td>CR2 存缺页地址，RDI 传 InterruptFrame*</td></tr><tr><td>关键指令</td><td>IRETQ, INT $3</td><td>中断返回（64位）和软件断点</td></tr><tr><td>extern &quot;C&quot;</td><td>C 链接约定</td><td>汇编调用 C 函数必须用 C 链接</td></tr></tbody></table><p>下一章（008_mini_kernel_disk_and_loader）我们会实现 ATA PIO 磁盘驱动和 ELF 加载器，让 mini kernel 能从磁盘加载大内核并跳转执行。届时 IDT 中已经配好的异常处理会继续发挥作用——大内核加载过程中的任何内存问题都能被 #PF 捕获并报告。</p><h2 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to &quot;延伸思考&quot;">​</a></h2><ul><li><strong>为什么不配 #GP（向量 13）？</strong> #GP（General Protection Fault）是内核开发中最常见的异常之一，几乎所有的段/权限错误都会触发它。添加 #GP 处理只需要多写一个 ISR stub 和一个 handle_gp 函数，和 #BP 的模式完全一样。建议作为课后练习自行添加。</li><li><strong>为什么 handle_pf 只打印不修复？</strong> 因为当前 mini kernel 还没有 VMM（虚拟内存管理器）。PMM 只管理物理页，没有页表映射的能力。在 milestone 016 实现 VMM 之后，handle_pf 会变成缺页处理的核心——根据 CR2 地址分配新页、修改页表项、然后 IRETQ 返回重试。</li><li><strong>如何测试 #PF？</strong> 你可以在 mini_kernel_main 里尝试访问一个无效地址（比如 <code>volatile int* p = (int*)0xDEADBEEF; *p = 42;</code>）。这会触发 #PF，串口会打印 CR2 地址（0xDEADBEEF）和错误码。但注意：因为 handle_pf 不修复页表，IRETQ 返回后会重新执行这条访存指令，形成死循环。要安全测试 #PF，你需要在 handle_pf 中修改 frame-&gt;rip 跳过触发指令。</li><li><strong>IRETQ 和 IRET 有什么区别？</strong> IRETQ 是 64 位版本的中断返回指令。它从栈上弹出 64 位的 RIP/CS/RFLAGS/RSP/SS（共 40 字节），而 IRET 只弹出 32 位的 EIP/CS/EFLAGS/ESP/SS（在 32 位保护模式下）。在 64 位内核中必须使用 IRETQ，用错会导致栈错位和 triple fault。</li></ul>`,80)])])}const b=e(r,[["render",i]]);export{u as __pageData,b as default};
